def gen(rng, size):
    n = max(1, min(size, 100000))
    return [''.join(rng.choice('01') for _ in range(n))]

oracle_python:
class Solution:
    def minimumSteps(self, s):
        n = len(s)
        total = 0
        for i in range(n):
            if s[i] == '1':
                for j in range(i + 1, n):
                    if s[j] == '0':
                        total += 1
        return total

solutions.python:
class Solution:
    def minimumSteps(self, s):
        ones = 0
        moves = 0
        for ch in s:
            if ch == '1':
                ones += 1
            else:
                moves += ones
        return moves

